import{_ as a,c as s,a1 as t,o as i}from"./chunks/framework.DiyHpDmR.js";const g=JSON.parse('{"title":"sidecar-agent 部署","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/sidecar-agent.md","filePath":"deploy/sidecar-agent.md","lastUpdated":1783292246000}'),n={name:"deploy/sidecar-agent.md"};function d(l,e,o,c,r,p){return i(),s("div",null,e[0]||(e[0]=[t(`<h1 id="sidecar-agent-部署" tabindex="-1">sidecar-agent 部署 <a class="header-anchor" href="#sidecar-agent-部署" aria-label="Permalink to &quot;sidecar-agent 部署&quot;">​</a></h1><p><code>sidecar-agent</code> 是裸机 / IDC 场景下的本机控制面代理。它连接同机业务服务、本机 Envoy、共享 Consul 和可观测组件，负责 register / drain / deregister、watch/replay、xDS、健康探测和恢复视图。它与 CoreDNS、nftables 和两个 Envoy 的完整关系见 <a href="./traffic-topology">流量拓扑</a>。</p><p>它通过 Envoy admin <code>/ready</code> 观察外部 Envoy 状态；默认探测间隔为 <code>2s</code>，只影响 readiness 摘要，不参与每次业务请求转发。</p><p>它不是配置中心、不是 north-south 全局网关，也不是完整 service mesh 平台。</p><h2 id="部署模式" tabindex="-1">部署模式 <a class="header-anchor" href="#部署模式" aria-label="Permalink to &quot;部署模式&quot;">​</a></h2><p>当前推荐把基础设施和源码进程分开部署：</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">组成</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">Docker 基础设施</td><td style="text-align:left;">Consul、CoreDNS、sidecar-agent-envoy</td><td style="text-align:left;">来自 <code>/firefly/deploy/docker</code></td></tr><tr><td style="text-align:left;">源码进程</td><td style="text-align:left;"><code>sidecar-agent</code></td><td style="text-align:left;">从 <code>/firefly/golang/sidecar-agent</code> 构建运行</td></tr><tr><td style="text-align:left;">可观测组件</td><td style="text-align:left;">OTel Collector、Prometheus 等</td><td style="text-align:left;">按环境需要独立启动</td></tr></tbody></table><p>启动命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> firefly/golang/sidecar-agent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./cmd/server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conf/bootstrap.json</span></span></code></pre></div><h2 id="关键端口" tabindex="-1">关键端口 <a class="header-anchor" href="#关键端口" aria-label="Permalink to &quot;关键端口&quot;">​</a></h2><p>标准配置中常用端口包括：</p><ul><li><code>18600</code>：sidecar-agent admin HTTP。</li><li><code>18601</code>：sidecar-agent xDS gRPC。</li><li><code>18502</code>：本机 Envoy listener。</li><li><code>18503</code>：本机 Envoy admin。</li><li><code>127.0.0.1:53</code>：节点级 CoreDNS DNS 入口。</li><li><code>18508/18509</code>：CoreDNS health / ready。</li><li><code>18510</code>：CoreDNS Prometheus metrics。</li><li><code>18500</code>：Consul HTTP。</li></ul><p>实际开放策略以仓库的 <code>PORTS.md</code> 和部署配置为准。</p><h2 id="业务服务接入" tabindex="-1">业务服务接入 <a class="header-anchor" href="#业务服务接入" aria-label="Permalink to &quot;业务服务接入&quot;">​</a></h2><p>业务服务通过 <code>go-consul/agent</code> 与本机 <code>sidecar-agent</code> 交互：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>go-layout</span></span>
<span class="line"><span>  -&gt; go-consul/agent</span></span>
<span class="line"><span>  -&gt; POST /register</span></span>
<span class="line"><span>  -&gt; GET /watch</span></span>
<span class="line"><span>  -&gt; POST /drain</span></span>
<span class="line"><span>  -&gt; POST /deregister</span></span></code></pre></div><p>服务能力来源是业务构建产物中的 <code>dep/protobuf/gen/gateway.manifest.json</code>。<code>sidecar-agent</code> 会把服务注册事实和 route document 写入 Consul，供东西向 Envoy 和 <code>api-gateway</code> 消费。</p><h2 id="数据面协作" tabindex="-1">数据面协作 <a class="header-anchor" href="#数据面协作" aria-label="Permalink to &quot;数据面协作&quot;">​</a></h2><p><code>sidecar-agent</code> 只控制 <code>sidecar-agent-envoy</code>，不控制 <code>api-gateway-envoy</code>。当前 Envoy bootstrap 中 <code>node.id</code> 为 <code>sidecar-agent-envoy</code>，静态 xDS cluster 连接宿主机 <code>host.docker.internal:18601</code>；Compose 对宿主机发布 <code>18502</code> 数据面入口和 <code>18503</code> admin。</p><p>服务间透明调用由 CoreDNS 和 nftables 把 <code>*.svc.cluster.local:9090</code> 导入本机 <code>sidecar-agent-envoy:18502</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Service DNS:9090</span></span>
<span class="line"><span>  -&gt; CoreDNS 返回 127.255.0.1</span></span>
<span class="line"><span>  -&gt; nftables redirect 到 127.0.0.1:18502</span></span>
<span class="line"><span>  -&gt; sidecar-agent-envoy 根据 xDS 转发到真实 endpoint</span></span></code></pre></div><h2 id="验收命令" tabindex="-1">验收命令 <a class="header-anchor" href="#验收命令" aria-label="Permalink to &quot;验收命令&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18600/healthz</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18600/readyz</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18600/debug/runtime</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18600/debug/services</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:18600/debug/xds</span></span></code></pre></div><p><code>/healthz</code> 只表示进程存活，<code>/readyz</code> 表示 sidecar 主链就绪。排障时优先看 <code>/debug/runtime</code> 和 <code>/debug/recovery</code>。</p><h2 id="当前边界" tabindex="-1">当前边界 <a class="header-anchor" href="#当前边界" aria-label="Permalink to &quot;当前边界&quot;">​</a></h2><ul><li>authz 按普通业务服务注册，<code>sidecar-agent</code> 不给它注入静态兜底地址。</li><li><code>sidecar-agent</code> 不提供 DNS server；节点级 DNS 由 CoreDNS 承担，透明导流由 nftables 和 Envoy 承担。</li><li>ext_authz 固定 fail-close；authz 不可达时 Envoy 请求会失败。</li><li><code>Authorization</code> 不作为 Firefly current 身份入口，不应配置为默认 ext_authz 透传头。</li><li><code>x-request-id</code> 只用于 Envoy 或日志关联；主 trace 传播使用 <code>traceparent</code>、<code>tracestate</code> 和 <code>baggage</code>。</li></ul>`,26)]))}const k=a(n,[["render",d]]);export{g as __pageData,k as default};
